Here's a strictly-typed email validation function using discriminated unions:

```typescript
// email-validator.ts

interface ValidationSuccess {
  valid: true;
  email: string;
  normalized: string;
}

interface ValidationFailure {
  valid: false;
  email: string;
  errors: ValidationError[];
}

interface ValidationError {
  code: EmailErrorCode;
  message: string;
}

type EmailErrorCode =
  | "EMPTY"
  | "NO_AT_SIGN"
  | "MULTIPLE_AT_SIGNS"
  | "EMPTY_LOCAL"
  | "EMPTY_DOMAIN"
  | "LOCAL_TOO_LONG"
  | "DOMAIN_TOO_LONG"
  | "INVALID_LOCAL_CHARS"
  | "INVALID_DOMAIN"
  | "CONSECUTIVE_DOTS"
  | "LEADING_TRAILING_DOT";

type EmailValidationResult = ValidationSuccess | ValidationFailure;

const MAX_LOCAL_LENGTH = 64;
const MAX_DOMAIN_LENGTH = 253;
const LOCAL_VALID_PATTERN = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+$/;
const DOMAIN_VALID_PATTERN = /^[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

function validateEmail(input: string): EmailValidationResult {
  const email = input.trim();
  const errors: ValidationError[] = [];

  if (email.length === 0) {
    return { valid: false, email, errors: [{ code: "EMPTY", message: "Email is empty" }] };
  }

  const atCount = email.split("@").length - 1;

  if (atCount === 0) {
    errors.push({ code: "NO_AT_SIGN", message: "Missing @ symbol" });
    return { valid: false, email, errors };
  }

  if (atCount > 1) {
    errors.push({ code: "MULTIPLE_AT_SIGNS", message: "Multiple @ symbols found" });
    return { valid: false, email, errors };
  }

  const atIndex = email.indexOf("@");
  const local = email.slice(0, atIndex);
  const domain = email.slice(atIndex + 1);

  if (local.length === 0) {
    errors.push({ code: "EMPTY_LOCAL", message: "Local part is empty" });
  }

  if (domain.length === 0) {
    errors.push({ code: "EMPTY_DOMAIN", message: "Domain part is empty" });
  }

  if (local.length > MAX_LOCAL_LENGTH) {
    errors.push({ code: "LOCAL_TOO_LONG", message: `Local part exceeds ${MAX_LOCAL_LENGTH} characters` });
  }

  if (domain.length > MAX_DOMAIN_LENGTH) {
    errors.push({ code: "DOMAIN_TOO_LONG", message: `Domain exceeds ${MAX_DOMAIN_LENGTH} characters` });
  }

  if (local.length > 0 && !LOCAL_VALID_PATTERN.test(local)) {
    errors.push({ code: "INVALID_LOCAL_CHARS", message: "Local part contains invalid characters" });
  }

  if (local.includes("..")) {
    errors.push({ code: "CONSECUTIVE_DOTS", message: "Local part contains consecutive dots" });
  }

  if (local.startsWith(".") || local.endsWith(".")) {
    errors.push({ code: "LEADING_TRAILING_DOT", message: "Local part starts or ends with a dot" });
  }

  if (domain.length > 0 && !DOMAIN_VALID_PATTERN.test(domain)) {
    errors.push({ code: "INVALID_DOMAIN", message: "Domain is not valid" });
  }

  if (errors.length > 0) {
    return { valid: false, email, errors };
  }

  return {
    valid: true,
    email,
    normalized: `${local.toLowerCase()}@${domain.toLowerCase()}`,
  };
}

export { validateEmail };
export type { EmailValidationResult, ValidationSuccess, ValidationFailure, ValidationError, EmailErrorCode };
```

**Usage with type narrowing:**

```typescript
const result = validateEmail("jm@example.com");

if (result.valid) {
  // TypeScript narrows to ValidationSuccess
  console.log(result.normalized); // "jm@example.com"
} else {
  // TypeScript narrows to ValidationFailure
  result.errors.forEach(e => console.log(`${e.code}: ${e.message}`));
}
```

📖 STORY EXPLANATION:
1. Uses a discriminated union on `valid: true | false` for exhaustive type narrowing
2. `EmailErrorCode` is a string literal union — no magic strings, fully autocomplete-friendly
3. Collects all errors per validation rather than failing on first — better UX for forms
4. Early returns for structural failures (empty, no @, multiple @) before deeper checks
5. Local part validation follows RFC 5321 allowed characters
6. Domain validation requires proper label structure and TLD of 2+ chars
7. Returns a `normalized` lowercase form on success for consistent storage/comparison
8. All types are exported for consumers to use in their own type narrowing

